class Solution:
    def doesValidArrayExist(self, derived):
        n = len(derived)
        for start in (0, 1):
            orig = [start]
            for i in range(n - 1):
                orig.append(derived[i] ^ orig[-1])
            if (orig[-1] ^ orig[0]) == derived[-1]:
                return True
        return False

